import java.util.*;

public class Main {
    private static int[] computeLPS(String pat) {
        int m = pat.length();
        int[] lps = new int[m];
        int len = 0;
        for (int i = 1; i < m; ) {
            if (pat.charAt(i) == pat.charAt(len)) {
                len++;
                lps[i] = len;
                i++;
            } else {
                if (len != 0) {
                    len = lps[len - 1];
                } else {
                    lps[i] = 0;
                    i++;
                }
            }
        }
        return lps;
    }

    private static int kmpSearch(String txt, String pat) {
        int n = txt.length();
        int m = pat.length();
        if (m == 0) return 0;
        int[] lps = computeLPS(pat);
        int i = 0, j = 0;
        while (i < n) {
            if (txt.charAt(i) == pat.charAt(j)) {
                i++; j++;
                if (j == m) {
                    return i - j;
                }
            } else {
                if (j != 0) {
                    j = lps[j - 1];
                } else {
                    i++;
                }
            }
        }
        return -1;
    }

    public static void main(String[] args) throws Exception {
        // Use a Scanner with a delimiter that treats both real whitespace and the literal "\\n" as separators.
        Scanner sc = new Scanner(System.in);
        sc.useDelimiter("\\s+|\\\\n"); // split on whitespace or the two‑character sequence "\\n"
        if (!sc.hasNextInt()) return;
        int T = sc.nextInt();
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            if (!sc.hasNext()) break;
            String text = sc.next();
            if (!sc.hasNext()) break;
            String pattern = sc.next();
            int ans = kmpSearch(text, pattern);
            out.append(ans);
            if (t + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

